function findRowInDoc(docContent, searchValue) {
  let tableIndex = 0;

  // Чистим searchValue от любых невидимых символов
  const cleanSearch = searchValue.replace(/\s+/g, '').trim();

  for (const element of docContent) {
    if (!element.table) continue;

    const table = element.table;
    const rows = table.tableRows || [];

    for (let rowIndex = 0; rowIndex < rows.length; rowIndex++) {
      const cells = rows[rowIndex].tableCells || [];

      if (!cells[5]) continue;

      let cellText = "";
      for (const contentItem of cells[5].content || []) {
        for (const el of contentItem.paragraph?.elements || []) {
          cellText += el.textRun?.content || "";
        }
      }

      // Чистим текст ячейки от любых невидимых символов
      const cleanCell = cellText.replace(/\s+/g, '').trim();

      if (cleanCell === cleanSearch) {
        return {
          found: true,
          tableIndex,
          rowIndex,
          tableStartIndex: element.startIndex
        };
      }
    }

    tableIndex++;
  }

  return { found: false, searchValue, cleanSearch };
}

const docContent = $input.first().json.body.content;
const searchValue = $('InputData').first().json.data.person.variables["<<РегНомерУд>>"];

return [{ json: findRowInDoc(docContent, searchValue) }];

function findTableStartIndexByHashColumn(doc) {
  const content = doc.body.content;

  for (const block of content) {
    if (!block.table) continue;

    const rows = block.table.tableRows;
    if (!rows || rows.length === 0) continue;

    const firstRow = rows[0];
    if (!firstRow.tableCells || firstRow.tableCells.length === 0) continue;

    const firstCell = firstRow.tableCells[0];
    const cellText = firstCell.content
      ?.flatMap(p => p.paragraph?.elements ?? [])
      ?.map(el => el.textRun?.content ?? "")
      ?.join("")
      ?.trim();

    if (cellText === "№") {
      return [{ tableStartIndex: block.startIndex }];
    }
  }

  return [{ tableStartIndex: null }];
}

return findTableStartIndexByHashColumn($input.first().json);

function buildBatchRequests(doc, values) {
  const content = doc.body.content;

  for (const block of content) {
    if (!block.table) continue;

    const rows = block.table.tableRows;
    if (!rows || rows.length === 0) continue;

    const firstRow = rows[0];
    if (!firstRow.tableCells || firstRow.tableCells.length === 0) continue;

    const firstCell = firstRow.tableCells[0];
    const cellText = firstCell.content
      ?.flatMap(p => p.paragraph?.elements ?? [])
      ?.map(el => el.textRun?.content ?? "")
      ?.join("")
      ?.trim();

    if (cellText !== "№") continue;

    const newRow = rows[1];
    if (!newRow?.tableCells) return { requests: null };

    // Собираем индексы и значения, затем разворачиваем для вставки с конца
    const requests = [...newRow.tableCells]
      .map((cell, i) => ({
        index: cell.content?.[0]?.paragraph?.elements?.[0]?.startIndex ?? null,
        value: values[i] ?? ""
      }))
      .filter(item => item.index !== null && item.value !== "")
      .sort((a, b) => b.index - a.index) // с конца!
      .map(item => ({
        insertText: {
          location: { index: item.index },
          text: item.value
        }
      }));

    return { requests };
  }

  return { requests: null };
}


const person_data = $("InputData").first().json.data.person;
const fio = `${person_data.fio.surname} ${person_data.fio.name} ${person_data.fio.patronymic}`;
const job_post = person_data.variables['<<Должность>>'];
const company = person_data.variables['<<Компания>>'];
const ud_reg_num = person_data.variables['<<РегНомерУд>>'];
const program_template = person_data.variables['<<Шаблон программы>>'];
const grp = $('InputData').first().json.data.key;
const OTV_ARRAY = ["Б1", "Б2", "Б3 3-5", "Б3 3-1", "Б3 3-4", "Б3 3-3", "Б3 3-2", "Б3 3-6", "Б3 1-6", "ОТВ А", "А1", "А2", "А3 1-6"];


// Значения для 9 ячеек по порядку столбцов
const values = [
  "0",                    // №
  fio, // Ф.И.О.
  job_post,            // Должность
  company,    // Место работы
  "удовлетворительно",    // Результат
  ud_reg_num,              // № удостоверения
  "",                     // Рег. номер
  OTV_ARRAY.includes(grp) ? program_template : 'Первичная',     // Решение
  ""                      // Подпись
];


return buildBatchRequests($input.item.json, values);

const doc = $input.first().json;

const content = doc.body.content;
const table = content
  .find(el => el.table && el.table.columns === 9)?.table;

if (!table) throw new Error("Таблица не найдена");

const updates = [];
for (let i = table.tableRows.length - 1; i >= 1; i--) {
  const cell = table.tableRows[i].tableCells[0];
  const textRun = cell.content[0].paragraph.elements
    .find(el => el.textRun && el.textRun.content !== "\n");

  const newText = String(i);

  if (textRun) {
    updates.push({
      startIndex: textRun.startIndex,
      endIndex: textRun.endIndex - 1, // убираем \n из диапазона
      text: newText,
      hasContent: true
    });
  } else {
    const insertIndex = cell.content[0].paragraph.elements[0].startIndex;
    updates.push({
      startIndex: insertIndex,
      endIndex: null,
      text: newText,
      hasContent: false
    });
  }
}

const requests = updates.flatMap(({ startIndex, endIndex, text, hasContent }) => {
  const ops = [];
  if (hasContent) {
    ops.push({
      deleteContentRange: {
        range: { startIndex, endIndex }
      }
    });
  }
  ops.push({
    insertText: {
      location: { index: startIndex },
      text
    }
  });
  return ops;
});

return [{ json: { requests } }];

const searchData = $('SearchExistingVyp').all();
const personData = $('InputData').first();
const searchKey = `ВЫПИСКА ${personData.json.data.key} ${personData.json.data.company.replace('"','«').replace('"','»')} ${personData.json.data.person.variables["<<Дата>>"].replaceAll(".","-")}`;

let rs;

for (let searchResult of searchData) {
  if (searchResult.json.name.includes(searchKey)) {
    rs = [searchResult];
  }
};

if (rs) {
  return rs; 
} else {
  return [{}]
}

